var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"바리케이드가 돌파당했습니다! 저희 장비만으로는 역부족입니다!","JPN":"バリケードが突破されました！　我々の装備だけでは力不足です！","ENG":"The barricade has been breached! We can't stop her with our equipment!","TWN":"路障被衝破了！ 光憑我們的裝備根本不夠！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"형님! 강소영 경위와 이유미 경정이 저희보다 먼저 뒤쫓아갔습니다!","JPN":"兄貴！　マエカワ警部補とカスカベ警視が私たちより先に追いかけていきました！","ENG":"Sir! Lieutenant Kang and Major Lee are already on her tail!","TWN":"大哥！姜素英警衛和李悠美警政，比我們早一步追上去了！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DRONE_TIDE_NULL_NULL","text":{"KOREA":"용의자 발견. 제철소로 진입하는 모습이 카메라에 촬영되었습니다.","JPN":"容疑者を発見。製鉄所に入る姿が撮影されました。","ENG":"Suspect sighted. There's camera footage of her entering the steel mill.","TWN":"發現嫌犯，鏡頭有拍到進去鐵工廠的身影。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRONE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_10"},{"id":"L7_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"좋아! 다들 두 사람을 도우러 간다!","JPN":"よし！　全員二人の応援に当たるぞ！","ENG":"Great! Let's go help the two police officers!","TWN":"很好！全都去幫她們兩個！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"꺄악……!","JPN":"きゃっ……！","ENG":"Eeek…!","TWN":"啊啊……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 일어설 수 있겠어요?!","JPN":"警視様、立てそうですか？","ENG":"Major, think can you get up?","TWN":"警政大人，你站得起來嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그보다 방금 장외 홈런 맞은 야구공처럼 날아오시던데요?","JPN":"まるで場外ホームランの野球ボールみたいに飛んで来ましたね！","ENG":"By the way, you just got hurled across the room like a baseball.","TWN":"不過，你剛剛整個就像被擊出場外全壘打的棒球一樣，飛得好高好遠喔！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"누가 야구공이야! 근무 시간에 야구나 보고 있으니까 그런 소리가 나오지!","JPN":"誰が野球ボールよ！　勤務時間に野球試合ばかり見てるからそんなくだらない話に例えるのよ！","ENG":"I'm no baseball! This is all because you never stop watching those baseball videos, even when you're on duty!","TWN":"誰是棒球啦！你是不是上班時間都在偷看棒球，開口閉口就是棒球！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신은 제가 만난 경찰 중에서도 유달리 끈질기군요. 젊음의 힘입니까.","JPN":"私がこれまで経験した警察の中でも、あなたは特にしつこいですね。これが若さということでしょうか。","ENG":"You're more tenacious than any other police officer I've encountered. Is it perhaps thanks to your youthful vigor?","TWN":"你在我遇過的警察中算是特別有毅力的，這是年輕的本事嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"계속 방해하려 하신다면…… 저도 이제 타박상 수준에서 그치지 않겠습니다.","JPN":"邪魔し続けるなら……私も打撲傷程度の攻撃で終わりません。","ENG":"If you insist on interfering, however… I'll have to leave you more than bruises.","TWN":"但如果你再妨礙我……可能就不會只是一般的跌打損傷了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"손가락 하나 못 움직이게 <color=#ffd34c>결박 플레이</color>해 드리죠.","JPN":"指一本動かせない<color=#ffd34c>束縛プレイ</color>を披露しましょう。","ENG":"I'll leave you in <color=#ffd34c>bondage</color> so you couldn't even lift a finger.","TWN":"我會和你玩<color=#ffd34c>綑綁遊戲</color>，讓你連一根手指也動不了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제 뒤로 오세요, 경정님!","JPN":"私の後ろへ、警視様！","ENG":"Get behind me, Major!","TWN":"警政大人，快躲到我後面！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저리 비켜……! 무능력자 주제에 어쩌려고!","JPN":"退いて……！　無能力者のくせにどうするつもりなの！","ENG":"Step aside! What's an incompetent like you going to do?!","TWN":"你走開啦…！那麼沒用，躲你後面要幹嘛！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"알아요! 하지만 경정님을 묶어놔도 되는 건 저뿐이니까요!","JPN":"わかってます！　でも警視様を束縛していいのは私だけですから！","ENG":"I know! But I'm the only one who gets to tie you up!","TWN":"我知道！但是只有我可以把警政大人綁起來！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런 상황에 농담이 나와, 강소영 경위?!","JPN":"こんな状況でよくそんな冗談が言えるわね！？","ENG":"Now's not the time for dirty jokes, Lieutenant!","TWN":"姜素英警衛，這種時候你還有心情開玩笑？！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"긴급 상황! 용의자가 경찰 분들을 공격하려 합니다!","JPN":"緊急事態！　容疑者が警察を攻撃しようとしています！","ENG":"We got a situation! The suspect is about to attack the police officers!","TWN":"緊急情況！嫌犯企圖攻擊警察！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"확인했다! 전원 사격 개시!","JPN":"確認した！　総員射撃開始！","ENG":"Confirmed! Everyone, open fire!","TWN":"收到！全員發射！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"일반적인 개인화기로 제게 타격을 주는 것은 불가능합니다. 이미 경험하셨을 텐데요.","JPN":"一般的な小火器で私にダメージを与えることは不可能です。すでに経験済みだと思いますが。","ENG":"Ordinary small arms have no effect on me. I thought you would have had learned that by now.","TWN":"普通的個人武器是不可能打到我的，你們剛應該有經歷到吧？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 당신들과 교전할 의향이 없습니다. 그러니……","JPN":"私はあなたたちと交戦する意向がありません。なので……","ENG":"I have no intent of engaging in hostilities with you. So if you could…","TWN":"我沒有要和你們開戰的意思，所以……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":" 윽!?","JPN":"うっ！？","ENG":" Ugh!","TWN":"唔！？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_08"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>사고회로의 과부하 감지. 원인을 파악 중입니다.</color>","JPN":"<color=#ff3636>思考回路の過負荷感知。原因を把握中です。</color>","ENG":"<color=#ff3636>Reasoning system overloaded. Running diagnostics…</color>","TWN":"<color=#ff3636>思考迴路超載，正在調查原因。</color>"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>침식파에 노출된 상태로 기동시간이 한계에 달했습니다. 사고회로 재기동. 재기동. 재기동.</color>","JPN":"<color=#ff3636>侵食波にさらされた状態での起動時間が限界に達しました。思考回路再起動。再起動。再起動。</color>","ENG":"<color=#ff3636>System operation timed out due to exposure to Corruption Rays. Reinitializing reasoning system. Reinitialize. Reinitialize.</color>","TWN":"<color=#ff3636>暴露在侵蝕波的狀態下，運作時間已達到極限。將重新啟動…重新啟動…重新啟動。</color>"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저 녀석, 갑자기 휘청거리고 있어……?","JPN":"あいつ、急にふらついている……？","ENG":"Is it me, or is she suddenly getting all wobbly…?","TWN":"那傢伙怎麼好像怪怪的……？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭔가…… 공격이 통하는 것 같지 않아요?","JPN":"なんだか……攻撃が効いている気がしませんか？","ENG":"It's as if… our attacks are working?","TWN":"不覺得……攻擊好像沒用嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Ugh…!","TWN":"唔……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>강제 재기동 절차를 시행합니다. 예상 소요 시간 ███,███시간.</color>","JPN":"<color=#ff3636>強制再起動手続きを行います。予想所要時間 ███、███時間。</color>","ENG":"<color=#ff3636>Force reinitializing… Estimated time: ███,███ hours.</color>","TWN":"<color=#ff3636>實行強制重新啓動程序。預計需要 ███,███小時。</color>"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>재기동 절차까지 10, 9, 8, 7……</color>","JPN":"<color=#ff3636>再起動開始まで10、9、8、7……</color>","ENG":"<color=#ff3636>Beginning reinitialization sequence in 10, 9, 8, 7…</color>","TWN":"<color=#ff3636>距離重新啓動程序還有10、9、8、7……</color>"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"저 녀석, 도망치는 건가!","JPN":"あいつ、逃げようとしている！","ENG":"She's getting away!","TWN":"那傢伙逃跑了嗎！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"아니야, 저쪽으로 가면……!","JPN":"いや、あそこは……！","ENG":"No… That's the way to…","TWN":"不，再走下去……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"용광로로 떨어진다! 멈춰!","JPN":"溶鉱炉に落ちる！　止まれ！","ENG":"The blast furnace! Stop!","TWN":"會掉入熔鐵爐！站住！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아직은…… 잠들 수 없습니다.","JPN":"今はまだ……眠れません。","ENG":"It is still too early… to go to sleep.","TWN":"我還不能……睡。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"말도 안 돼……. 용광로에 뛰어들었다고?!","JPN":"そんな……溶鉱炉に飛び込んだの！？","ENG":"No way… She jumped into the furnace?!","TWN":"怎麼可能……她跳進熔鐵爐裡？！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"이런……! 당장 용광로를 멈추라고 해!","JPN":"しまった……！　今すぐ溶鉱炉を止めさせろ！","ENG":"Damn it…! Have them shut down the furnace right now!","TWN":"可惡……！立刻讓熔鐵爐停下來！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"형님! 카운터라도 저건 이미 틀렸습니다! 포기하십시오!","JPN":"兄貴！　いくらカウンターでもあれじゃ無理です！　諦めましょう！","ENG":"But sir… Even a Counter couldn't survive that! Just let it go!","TWN":"大哥！就算她是制裁者，但掉進去就沒救了！放棄吧！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"범인인지 아닌지도 아직 밝혀지지 않았다! 과잉대응이 문제였다면……!","JPN":"犯人なのかどうかまだ明らかになっていない！　もし過剰対応だったなら……！","ENG":"But we never even verified if she really was the culprit! If this turns out to be an abuse of excessive force…!","TWN":"都還沒查清楚她到底是不是犯人！ 是因為我們反應過當嗎……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아뇨. 당신들의 대응은 매우 적절했다고 판단됩니다.","JPN":"いいえ。あなたたちの対応はとても適切だったと判断されます。","ENG":"No. Your response has been most proportional.","TWN":"不，我認爲你們的反應是很恰當的。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_07"},{"id":"L24_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"용광로에서…… 멀쩡하게 걸어 나와? 내가 지금 늙어서 헛것을 보는 건가?","JPN":"溶鉱炉から……普通に出てきた！　私は今、幻を見ているのか？","ENG":"Did she… just walk out of the blast furnace? Am I seeing things in my old age?","TWN":"從熔鐵爐裡……沒事地走出來？我現在是老花眼嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"너 대체 뭐야! 경찰서로 가느니 불타 죽는 게 낫다는 거야?!","JPN":"あなたはいったい何者なの？　連行されるなら焼死したほうがマシだとでも思ったわけ！？","ENG":"What's your deal?! You'd rather melt yourself to death than get arrested?!","TWN":"你到底在做什麼！你情願被燒死，也不想去警察局嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"진공관 맙소사. 말씀이 심하시군요, 휴먼.","JPN":"オーマイ、真空管。言い過ぎですね、ヒューマン。","ENG":"Oh my diodes. That is quite the hyperbole, human.","TWN":"我的真空管。人類，這話有點嚴重。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자멸할 계획은 없었습니다. 저는 미래에서 오지도 않았고, 기계 시대의 도래를 막으려는 숭고한 목적도 없으니까요.","JPN":"自滅する計画はありませんでした。私は未来から来たわけではありませんし、機械時代の到来を防ごうとする崇高な目的もありませんので。","ENG":"I have no desire for self-destruction. I am neither from the future nor entrusted with the mission of preventing the Rise of Machines following Judgment Day.","TWN":"我沒有打算自我毀滅。因爲我並非來自未來，也沒有阻止機器時代來臨的崇高理想。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>인공지능 보호를 위해 강제 재기동 절차를 임시 중단합니다.</color>","JPN":"<color=#ff3636>人工知能保護のため、強制再起動手続きを一時中断します。</color>","ENG":"<color=#ff3636>Force reinitialization temporarily suspended to protect the A.I.</color>","TWN":"<color=#ff3636>為保護人工智慧，強行停止重新啟動程序。</color>"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>보다 효율적인 보호를 위해서는 재기동 절차가 필요합니다.</color>","JPN":"<color=#ff3636>より効率的な保護のためには再起動手続きが必要です。</color>","ENG":"<color=#ff3636>Reinitialization is required for more efficient protection.</color>","TWN":"<color=#ff3636>為提升保護效能，需進行重新啟動。</color>"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"다만 지금의 저에게 시간은 이터니움보다 귀중한 자원입니다. 여기서 한가하게 재기동이나 하면서 낭비할 수는 없습니다.","JPN":"しかし、今の私にとって時間はエタニウムよりも貴重な資源です。ここでのんびり再起動しながら時間を無駄にするわけにはいきません。","ENG":"Time, however, is an asset more precious than Eternium right now. I cannot afford to waste another second sitting here reinitializing.","TWN":"只是對於現在的我來說，時間是比永恆之金還要寶貴的資源。不能隨隨便便就在這裡重新啟動浪費掉。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신들도 저보다는 난민지구에 가 보십시오. 가서 제 결백을 증명해 주시면 감사하겠습니다.","JPN":"あなたたちにはここで私を問いただすより、難民地区に行くことをお勧めします。そこで、私の潔白を証明していただけると助かります。","ENG":"I suggest your attention is better spent on the refugee district than me as well. I would be grateful if you could go there and prove my innocence.","TWN":"請你們直接去難民區一趟吧，請去那裡證明我的清白，那我會很感謝你們。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잠깐! 용의자가 하는 말대로 해 줄 것 같아?! 멈춰!","JPN":"待って！　容疑者の言うとおりにすると思う！？　止まれ！","ENG":"Wait! You think we'd just do as a suspect says?! Stop right there!","TWN":"等等！你以為我們會照嫌犯的話去做嗎？站住！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 자. 경정님. 진정하세요. 저희가 할 수 있는 일은 다 했잖아요.","JPN":"まあまあ、警視様も落ち着いてください。私たちにできることは全部やったじゃないですか。","ENG":"There, there, Major. Cool it. We've already done all we can.","TWN":"好了好了，警政大人，冷靜點。 我們已經盡力了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"형님, 저렇게 자유분방한 레이디를 붙잡으려니 마음이 편치 않은데요.","JPN":"兄貴、あんなに自由奔放なレディーを捕らえるのはあまり気が進みませんね。","ENG":"Sir, I don't feel so good about trying to catch such a free-spirited gal.","TWN":"大哥，竟然要逮捕如此自由奔放的淑女，我於心不忍。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"그래. 추격은 여기서 중단하고 부상자들부터 수습한다.","JPN":"そうだな。追撃を取りやめて負傷者たちの収拾を優先する。","ENG":"Agreed. We will abort the pursuit here and tend to the wounded.","TWN":"好吧，那就不繼續追了，先處理傷者吧。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"……관리국에 알려야겠군. 얼치기 태스크포스가 달려들면 피해만 커지겠어.","JPN":"……管理局に知らせないとな。中途半端なタスクフォースカンパニーがあれにあたれば被害が大きくなるだけだ。","ENG":"…I guess I should alert the Administration. We'll end up with only more casualties if some third-rate TASKFORCEs keep lunging at her.","TWN":"……還是通知管理局吧。二百五特遣勢力再追下去的話，恐怕只會造成更多損失。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"좀 어때, 블랙 네트워크는.","JPN":"ブラックネットワークのほうはどう？","ENG":"How are things on the Dark Network?","TWN":"黑色網路上面現在怎麼樣？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"말도 마. 블랙 타이드 대원이 올린 글 때문에 아주 발칵 뒤집어졌어.","JPN":"大変なことになってるぞ。ブラックタイドの隊員の書き込みのせいで大騒ぎさ。","ENG":"Don't even get me started. This post by a Black Tide operative broke the Dark Network.","TWN":"炸了，因爲黑潮隊員上傳的貼文，整個吵翻天。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어때, 오르카. 너는 용광로에 들어가도 멀쩡하게 나올 수 있을 거 같아?","JPN":"どうだ、オルカ。お前は溶鉱炉に落ちても傷一つなしで出てこられるか？","ENG":"What do you think, Orca? Do you think you could crawl out of a blast furnace unscathed?","TWN":"奧爾卡，你覺得怎麼樣？你也可以跳進熔鐵爐後，沒事地走出來嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"애한테 못하는 소리가 없어. 그 주둥이는 말조심 하면 병이라도 걸리냐?","JPN":"子どもに何いってんの。その明太子みたいな口はくだらない質問をするために付いてるの？","ENG":"Stop feeding that crap to the kid. When will you ever learn to keep that mouth of yours shut?","TWN":"你幹嘛問一個孩子那種問題？你那張嘴說話小心點會死嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"왜 나한테만 뭐라고 해. 멀쩡한 수송기까지 덥석 맡긴 사람이.","JPN":"なんだよ、冷たいな。ノコノコと輸送機まで渡したやつに言われてもな。","ENG":"You don't get to lecture me. I'm not the one who gave away a perfectly fine plane.","TWN":"幹嘛只念我，你還不是連好好的運輸機都拿去託運。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"여기서 할 일은 다 끝났는데, 돌아갈 때는 어떡할 거야?","JPN":"ここでの仕事は終わったんだが、どうやって帰るつもりだ？","ENG":"Our work here is done. How are we supposed to get back now?","TWN":"現在這裡的工作都做完了，要怎麼回去？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"급한 대로 여객기 표 구해 뒀어. 두 장뿐이지만.","JPN":"取り急ぎ旅客機のチケットは確保できたの。二枚しかないけど。","ENG":"I managed to score some tickets for a commercial airliner. Except there's only two.","TWN":"臨時弄到客機的機票，但只有兩張。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"오, 진짜? 그러면 나머지 한 명은?","JPN":"おお、やるじゃないか！　じゃあ、残りの一人はどうするんだ？","ENG":"Dang, for real? Then what about the third wheel?","TWN":"喔，真的嗎？那剩下的那個人怎麼辦？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐 그런 당연한 걸 묻고 그래. 네가 짐칸에 타면 되지.","JPN":"当たり前のこと聞かないで。あんたが貨物室に乗るに決まってるでしょ。","ENG":"Do I need to spell it out for you? You can stow away in our luggage.","TWN":"答案這麼明顯還有什麼好問的，當然是你坐貨艙囉。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하아……. 그럴 줄 알았지.","JPN":"はあ……やっぱりそういうことか。","ENG":"Ugh… I knew it.","TWN":"哀……我就知道會這樣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"저 녀석이 한 말은 무시해, 오르카. 하여간 푼수끼는 여전하다니까.","JPN":"あいつの話は無視してね、オルカ。まったく、大人気ないんだから。","ENG":"Don't pay any attention to what he said, Orca. He just never learns, does he.","TWN":"奧爾卡，那傢伙說的話你不用放心上，反正他就是頭腦簡單四肢發達。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"<color=#ff3636>오르카</color>가…… 이상하대.","JPN":"<color=#ff3636>オルカ</color>が……おかしいって。","ENG":"<color=#ff3636>Orca</color>… says something's strange.","TWN":"<color=#ff3636>奧爾卡</color>說……很奇怪。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"응? 이상하다니, 뭐가?","JPN":"えっ？　おかしい？　何が？","ENG":"Hm? What do you mean, strange?","TWN":"嗯？哪裡奇怪？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그 언니…….","JPN":"あのお姉さん……","ENG":"That girl…","TWN":"那個姊姊……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"원래는 예전에 죽은 거래.","JPN":"元々昔に死んでるんだって。","ENG":"She already died long ago.","TWN":"原本應該是死掉的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};